 1	import { type FC, useState } from 'react';
 2	
 3	import SectionHeading from '@components/headers/SectionHeading';
 4	import { Bullseye, PageSection } from '@patternfly/react-core';
 5	import { isEmpty } from '@utils/helpers';
 6	import { useForkliftTranslation } from '@utils/i18n';
 7	
 8	import { usePlan } from '../../hooks/usePlan';
 9	import type { PlanPageProps } from '../../utils/types';
10	
11	import MappingAlerts from './components/MappingAlerts';
12	import PlanMappingsSection from './components/PlanMappingsSection';
13	import { useMappingResources } from './hooks/useMappingResources';
14	import { getMappingAlerts, getMappingPageMessage } from './utils/utils';
15	
16	const PlanMappingsPage: FC<PlanPageProps> = ({ name, namespace }) => {
17	  const { t } = useForkliftTranslation();
18	  const { plan } = usePlan(name, namespace);
19	  const [alert, setAlert] = useState<string>('');
20	
21	  const {
22	    loadingResources,
23	    planNetworkMap,
24	    planStorageMap,
25	    resourcesError,
26	    sourceNetworks,
27	    sourceStorages,
28	    targetNetworks,
29	    targetStorages,
30	  } = useMappingResources(plan);
31	
32	  const message = getMappingPageMessage({
33	    loadingResources,
34	    networkMapsEmpty: isEmpty(planNetworkMap),
35	    resourcesError,
36	    storageMapsEmpty: isEmpty(planStorageMap),
37	  });
38	
39	  if (message) {
40	    return (
41	      <Bullseye>
42	        <span className="text-muted">{message}</span>
43	      </Bullseye>
44	    );
45	  }
46	
47	  return (
48	    <PageSection variant="light" data-testid="plan-mappings-section">
49	      <MappingAlerts
50	        alerts={[
51	          ...getMappingAlerts({
52	            resourcesError,
53	            sourceNetworkEmpty: isEmpty(sourceNetworks),
54	            sourceStoragesEmpty: isEmpty(sourceStorages),
55	            targetStoragesEmpty: isEmpty(targetStorages),
56	          }),
57	          alert,
58	        ].filter(Boolean)}
59	      />
60	      <SectionHeading text={t('Mappings')} />
61	
62	      <PlanMappingsSection
63	        plan={plan}
64	        planNetworkMap={planNetworkMap!}
65	        planStorageMap={planStorageMap!}
66	        setAlertMessage={setAlert}
67	        sourceNetworks={sourceNetworks}
68	        sourceStorages={sourceStorages}
69	        targetNetworks={targetNetworks}
70	        targetStorages={targetStorages}
71	      />
72	    </PageSection>
73	  );
74	};
75	
76	export default PlanMappingsPage;

